export enum PaymentType {
  FISCAL = 'Fiscal (Impuestos)',
  PARAFISCAL = 'Parafiscal (SSO, INCES, etc.)',
  SERVICIO = 'Servicio Público',
  MUNICIPAL = 'Impuesto Municipal',
  OTRO = 'Otro'
}

export interface PaymentRecord {
  id: string;
  dateRegistered: string;
  organism: string;
  paymentType: PaymentType;
  amount: number;
  paymentDateReal: string;
  unitCode: string;
  unitName: string;
  municipality: string;
  status: 'Pending' | 'Paid';
}

export interface BudgetSummary {
  type: string;
  totalSpent: number;
  projectedAnnual: number;
  count: number;
}

import { PaymentType } from './types';

export const PAYMENT_TYPES = [
  PaymentType.FISCAL,
  PaymentType.PARAFISCAL,
  PaymentType.SERVICIO,
  PaymentType.MUNICIPAL,
  PaymentType.OTRO
];

export const INITIAL_FORM_STATE = {
  dateRegistered: new Date().toISOString().split('T')[0],
  organism: '',
  paymentType: PaymentType.FISCAL,
  amount: 0,
  paymentDateReal: new Date().toISOString().split('T')[0],
  unitCode: '',
  unitName: '',
  municipality: ''
};

// This is a placeholder. The user should input their own via the UI.
export const DEFAULT_SCRIPT_URL = '';

/**
 * Google Apps Script for FiscalControl Pro
 * Deploy this as a Web App with access set to "Anyone".
 */

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    const doc = SpreadsheetApp.getActiveSpreadsheet();
    const sheetName = 'RegistroPagos';
    let sheet = doc.getSheetByName(sheetName);

    // Create sheet and headers if they don't exist
    if (!sheet) {
      sheet = doc.insertSheet(sheetName);
      sheet.appendRow([
        'ID', 
        'Fecha Registro', 
        'Organismo', 
        'Tipo Pago', 
        'Monto', 
        'Fecha Pago Real', 
        'Código Unidad', 
        'Nombre Unidad', 
        'Municipio',
        'Timestamp'
      ]);
      // Style headers
      sheet.getRange(1, 1, 1, 10).setFontWeight('bold').setBackground('#1e3a8a').setFontColor('#ffffff');
    }

    const data = JSON.parse(e.postData.contents);

    sheet.appendRow([
      data.id,
      data.dateRegistered,
      data.organism,
      data.paymentType,
      data.amount,
      data.paymentDateReal,
      data.unitCode,
      data.unitName,
      data.municipality,
      new Date()
    ]);

    return ContentService.createTextOutput(JSON.stringify({ 'result': 'success', 'row': sheet.getLastRow() }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService.createTextOutput(JSON.stringify({ 'result': 'error', 'error': e }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  // Optional: Add logic here if you want to read data back from the sheet
   return ContentService.createTextOutput(JSON.stringify({ 'status': 'alive' }))
      .setMimeType(ContentService.MimeType.JSON);
}

import { PaymentRecord } from '../types';

export const saveToSheet = async (record: PaymentRecord, scriptUrl: string): Promise<boolean> => {
  if (!scriptUrl) {
    console.warn("No Script URL provided. Running in offline/demo mode.");
    return true; // Simulate success
  }

  try {
    // We use no-cors mode because Google Scripts doesn't support CORS headers for simple POSTs easily 
    // without a redirect. The standard workaround for 'success' confirmation is tricky in pure client-side.
    // However, text/plain is used to avoid preflight OPTIONS request.
    const response = await fetch(scriptUrl, {
      method: 'POST',
      body: JSON.stringify(record),
      headers: {
        'Content-Type': 'text/plain;charset=utf-8', 
      },
    });

    // In opaque mode (no-cors), we can't read the response status directly, 
    // but if it didn't throw, it likely reached the server.
    return true; 
  } catch (error) {
    console.error("Error saving to Google Sheet:", error);
    return false;
  }
};

import React, { useState } from 'react';
import { Save, Share2, Loader2 } from 'lucide-react';
import { PaymentRecord, PaymentType } from '../types';
